const res = ($input.first().json.results) || [];
const g = (pr,n,t) => { const x=pr[n]||{}; if(t==='title') return (x.title||[]).map(z=>z.plain_text).join(''); if(t==='rt') return (x.rich_text||[]).map(z=>z.plain_text).join(''); return ''; };
return res.map(p => ({ json: { page_id: p.id, topic: g(p.properties,'topic','title'), content_angle: g(p.properties,'content_angle','rt'), summary: g(p.properties,'summary','rt') } }));

const scored=$input.all();
const toItems=$('To items').all();
const min=$('Config').first().json.min_score||6;
const out=[];
for(let i=0;i<scored.length;i++){
  let s;
  try{ const raw=scored[i].json.candidates[0].content.parts[0].text; const clean=raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim(); s=JSON.parse(clean);}catch(e){ continue; }
  const t=+s.trend_score||0,u=+s.usefulness_score||0,v=+s.viral_score||0,pf=+s.product_fit_score||0;
  const total=+(t*0.2+u*0.3+v*0.25+pf*0.25).toFixed(2);
  const status=total>=min?'Scored':'Rejected';
  const ti=(toItems[i]||{}).json||{};
  if(!ti.page_id) continue;
  out.push({json:{page_id:ti.page_id,topic:ti.topic||'',total,status,props:{trend_score:{number:t},usefulness_score:{number:u},viral_score:{number:v},product_fit_score:{number:pf},total_score:{number:total},status:{select:{name:status}},why_now:{rich_text:[{text:{content:('score: '+(s.reason||'')).slice(0,1900)}}]},updated_at:{date:{start:new Date().toISOString()}}}}});
}
return out;
